INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('2a2c8a91-7f86-57e4-a6e7-b3f2fd901044', 'e5cf7677-1873-4e7a-ae65-3de4832151b1', 'You should ___ a bus to the museum today.', '你今天應該搭公車去博物館。', 'take', 'sing', 'eat', 'see', 'take 表示「搭乘」交通工具。', 'take a bus → 搭公車。'),
('c811cc48-dd2c-5162-a15c-2f143650f134', '3618111e-eb30-4e3b-b1bb-d7eb327585a6', 'I have a dog. ___ dog is big.', '我有一隻狗。我的狗很大。', 'my', 'your', 'his', 'her', 'my 為第一人稱單數的所有格，表示「我的」。', 'my (我的) → 記住 my 是用來指「我的」東西。'),
('ce1e93e7-6510-5562-97e6-622588d900b0', 'ab9949bb-c10f-4d67-8598-84d3e16ab7d5', 'The house ___ a beautiful garden is very expensive.', '那棟擁有美麗花園的房子非常貴。', 'with', 'by', 'for', 'at', '表示擁有或具有某種特徵。', '房子「帶有」花園。');
